import{_ as s,o as a,c as t,a2 as i}from"./chunks/framework.DBPoZGF_.js";const k=JSON.parse('{"title":"Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"auth.md","filePath":"auth.md","lastUpdated":1782036012000}'),n={name:"auth.md"};function o(l,e,r,h,p,d){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h1><p>The CLI authenticates to App Store Connect via API keys + JWT. This doc covers how to create the keys, what scopes they need, and how the CLI rotates them.</p><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Create a key on App Store Connect (see below)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Download the .p8 file to .secret-stuff/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Write .secret-stuff/appstore-config.yaml:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    issuer_id: &quot;&lt;your-issuer-uuid&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    app_id: &quot;&lt;numeric-app-id&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    keys:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#      app_manager:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#        key_id: &quot;ABCDE12345&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#        key_file: &quot;AuthKey_ABCDE12345.p8&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    default_key: &quot;app_manager&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. Smoke-test:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appstore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span></span></code></pre></div><h2 id="creating-a-key" tabindex="-1">Creating a key <a class="header-anchor" href="#creating-a-key" aria-label="Permalink to &quot;Creating a key&quot;">​</a></h2><p><a href="https://appstoreconnect.apple.com/access/api" target="_blank" rel="noreferrer">App Store Connect → Users and Access → Integrations → App Store Connect API</a>.</p><ol><li>Click <strong>Generate API Key</strong> (or <strong>+</strong> if you already have one).</li><li>Pick an <strong>access role</strong> — see below for what each role allows.</li><li>Download the <code>.p8</code> immediately. <strong>Apple shows it once.</strong> If you lose it, revoke and regenerate.</li><li>Note the <strong>Key ID</strong> (10 characters, shown next to the key name) and your <strong>Issuer ID</strong> (UUID at the top of the Keys page).</li><li>Drop the <code>.p8</code> in <code>.secret-stuff/</code> and reference its filename in <code>appstore-config.yaml</code>.</li></ol><h2 id="access-roles" tabindex="-1">Access roles <a class="header-anchor" href="#access-roles" aria-label="Permalink to &quot;Access roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>What the CLI can do</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>Everything. Avoid unless you need it for a one-off.</td></tr><tr><td><strong>App Manager</strong></td><td>Listings, IAPs, subscriptions, screenshots, custom product pages. <strong>Default choice for the CLI.</strong></td></tr><tr><td><strong>Developer</strong></td><td>Read-only on most things; cannot edit listings or push pricing.</td></tr><tr><td><strong>Marketer</strong></td><td>Listings + screenshots only. Useful for a &quot;marketing-only&quot; key that can&#39;t touch pricing.</td></tr><tr><td><strong>Customer Support</strong></td><td>Reads + responds to reviews. Not relevant to this CLI.</td></tr></tbody></table><p>For day-to-day use, <strong>App Manager</strong> is the right pick. The CLI will refuse to do something the key can&#39;t do — you&#39;ll get a 403 from ASC with a clear message.</p><h2 id="multiple-keys" tabindex="-1">Multiple keys <a class="header-anchor" href="#multiple-keys" aria-label="Permalink to &quot;Multiple keys&quot;">​</a></h2><p>You can configure multiple keys with different roles. Useful when you want a separate key for build uploads (often automated, in CI) from one for metadata edits:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">keys</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  build_upload</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    key_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AAAAA11111&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    key_file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AuthKey_AAAAA11111.p8&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  app_manager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    key_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;BBBBB22222&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    key_file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AuthKey_BBBBB22222.p8&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">default_key</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app_manager&quot;</span></span></code></pre></div><p>Pick a non-default key per call with <code>--key-id build_upload</code>, or set <code>APPSTORE_KEY_ID</code> for the whole shell.</p><h2 id="jwt-lifecycle" tabindex="-1">JWT lifecycle <a class="header-anchor" href="#jwt-lifecycle" aria-label="Permalink to &quot;JWT lifecycle&quot;">​</a></h2><p>The CLI generates a fresh JWT per command run (Apple tokens are valid for 20 minutes). The signing is done locally in-process — your <code>.p8</code> never leaves your machine. The token is:</p><ul><li><code>iss</code> — issuer ID from config</li><li><code>kid</code> — key ID from the selected key</li><li><code>aud</code> — <code>appstoreconnect-v1</code></li><li><code>exp</code> — <code>now + 19m</code> (1-minute safety margin under Apple&#39;s 20-minute limit)</li><li>Signed with <code>ES256</code> using the <code>.p8</code> private key</li></ul><p>There&#39;s nothing to refresh or cache. If a long-running operation crosses the 20-minute boundary, Apple will reject the call; the CLI surfaces the error and you re-run. (In practice, no single command takes that long — the slowest is a full <code>iap export</code> over 173 territories × 12 products, which is still under 2 minutes.)</p><h2 id="key-rotation" tabindex="-1">Key rotation <a class="header-anchor" href="#key-rotation" aria-label="Permalink to &quot;Key rotation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Generate a new key on ASC (don&#39;t revoke the old one yet)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Drop the new .p8 in .secret-stuff/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Add it as a new entry in appstore-config.yaml</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. Run a smoke test with --key-id &lt;new&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appstore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --key-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app_manager_v2</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 5. Once you&#39;ve confirmed it works, flip default_key + revoke the old one on ASC</span></span></code></pre></div><h2 id="validating-auth" tabindex="-1">Validating auth <a class="header-anchor" href="#validating-auth" aria-label="Permalink to &quot;Validating auth&quot;">​</a></h2><p>The CLI doesn&#39;t ship a dedicated <code>appstore auth</code> command (yet). The cheapest validation is <code>appstore info</code> — it makes a single read call and prints the bundle ID. If that returns, your auth is wired.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appstore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   &quot;id&quot;: &quot;1234567890&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   &quot;name&quot;: &quot;Your App&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   &quot;bundleId&quot;: &quot;com.you.yourapp&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   ...</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># }</span></span></code></pre></div><p>If you see <code>401 Unauthorized</code>, the most common causes:</p><ul><li><code>.p8</code> file doesn&#39;t match the <code>key_id</code> in your config</li><li>Issuer ID typo</li><li>Key was revoked or expired on ASC</li></ul><p>If you see <code>403 Forbidden</code>, the key doesn&#39;t have the role for the operation. Switch to a higher-privilege key or pick a different role for this key.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li><strong>Never commit <code>.p8</code> or <code>appstore-config.yaml</code>.</strong> The repo&#39;s <code>.gitignore</code> should include <code>.secret-stuff/</code> — verify before your first commit.</li><li>The CLI reads <code>.p8</code> files from disk on every command invocation. They&#39;re not cached in memory longer than the process lifetime.</li><li>JWTs are signed with the private key locally; the key is never sent to Apple.</li></ul><h2 id="env-var-overrides" tabindex="-1">Env-var overrides <a class="header-anchor" href="#env-var-overrides" aria-label="Permalink to &quot;Env-var overrides&quot;">​</a></h2><p>For CI or one-off scripts:</p><table tabindex="0"><thead><tr><th>Var</th><th>Effect</th></tr></thead><tbody><tr><td><code>APPSTORE_KEY_ID</code></td><td>Use this key name instead of the config&#39;s <code>default_key</code></td></tr><tr><td><code>APPSTORE_SECRETS_DIR</code></td><td>Override where to look for <code>appstore-config.yaml</code> + <code>.p8</code></td></tr><tr><td><code>APPSTORE_METADATA_DIR</code></td><td>Override where to find/write YAML metadata</td></tr></tbody></table>`,31)])])}const u=s(n,[["render",o]]);export{k as __pageData,u as default};
